#Requires -Version 7.4Set-StrictMode -Version Latest$ErrorActionPreference = 'Stop'BeforeAll {    $script:Here = Split-Path $PSCommandPath -Parent    $script:RepoRoot = Resolve-Path (Join-Path $script:Here '..' '..')    $script:Wrapper = Join-Path $script:RepoRoot 'modules' 'Invoke-Zizmor.ps1'}Describe 'Invoke-Zizmor: error paths' {    Context 'when zizmor CLI is missing' {        BeforeAll {            Mock Get-Command { return $null } -ParameterFilter { $Name -eq 'zizmor' }            $result = & $script:Wrapper        }        It 'returns Status = Skipped' {            $result.Status | Should -Be 'Skipped'        }        It 'returns empty Findings' {            @($result.Findings).Count | Should -Be 0        }        It 'includes message about zizmor not installed' {            $result.Message | Should -Match 'not installed'        }        It 'sets Source to zizmor' {            $result.Source | Should -Be 'zizmor'        }    }}